const eur = (n) => new Intl.NumberFormat('fr-FR',{style:'currency',currency:'EUR'}).format(n);
for (const item of $input.all()) {
  const j = item.json;
  const biens = (typeof j.biens === 'string' ? JSON.parse(j.biens) : j.biens) || [];
  const lignes = biens.map(b => '• ' + b.title + ' (' + (b.city||'') + ') — ' + eur(b.price) + ' [réf ' + (b.ref||'') + ']').join('
');
  item.json.subject = j.nb_biens > 1 ? (j.nb_biens + ' nouveaux biens correspondent à votre recherche') : 'Un nouveau bien correspond à votre recherche';
  item.json.body = 'Bonjour ' + j.first_name + ',

Voici les nouveautés qui correspondent à vos critères :

' + lignes + '

Répondez à cet email pour organiser une visite.

À bientôt,';
}
return $input.all();
